+fn resolve_evidence_path() -> Option<PathBuf> {
+    for key in ["FTUI_DEMO_EVIDENCE_JSONL", "FTUI_HARNESS_EVIDENCE_JSONL"] {
+        if let Ok(value) = std::env::var(key) {
+            let trimmed = value.trim();
